import torch
import torch.nn as nn

def get_optimizer(model, lr, optimizer='sgd', weight_decay=0, nesterov=False, momentum=0.9):
    if optimizer.lower() == 'adam':
        opt = torch.optim.Adam(model.parameters(), lr=lr, betas=(0.9, 0.999), eps=1e-08, weight_decay=weight_decay)
    elif optimizer.lower() == 'rmsprop':
        opt = torch.optim.RMSprop(model.parameters(), lr=lr, alpha=0.99, eps=1e-08, weight_decay=weight_decay, momentum=momentum)
    elif optimizer.lower() =='sgd' or optimizer is None:
        if weight_decay!= 0:
            g0, g1, g2 = [], [], []  # optimizer parameter groups
            for v in model.modules():
                if hasattr(v, 'bias') and isinstance(v.bias, nn.Parameter):  # bias
                    g2.append(v.bias)
                if isinstance(v, (nn.BatchNorm2d, nn.LayerNorm)):  # weight (no decay)
                    g0.append(v.weight)
                elif hasattr(v, 'weight') and isinstance(v.weight, nn.Parameter):  # weight (with decay)
                    g1.append(v.weight)

            opt = torch.optim.SGD(g0, lr, momentum=momentum, nesterov=nesterov)
            opt.add_param_group({'params': g1, 'weight_decay': weight_decay})  # add g1 with weight_decay
            opt.add_param_group({'params': g2})  # add g2 (biases)
        else:
            opt = torch.optim.SGD(model.parameters(), lr, momentum=momentum, nesterov=nesterov)
    else:
        raise ValueError('Invalid optimizer name')

    return opt
